  }

  if (context.component.requiresFigma && !context.figma?.available) {
    throw new Error(`Figma indisponible pour ${componentName} alors que le workflow exige un contexte Figma`);
  }

  outputItems.push({
    json: {
      ...data,
      mcpContext: context,
    },
  });
}

return outputItems;

