function sanitizeMarkdown(markdown) {
  const text = String(markdown || '').trim();
  if (!text) return '';

  const fenceCount = (text.match(/```/g) || []).length;
  if (fenceCount % 2 === 1) {
    return `${text}\n\`\`\`\n`;
  }

  return text;
}

